from collections import defaultdict

def detect_loops(tasks):
    delegation_graph = defaultdict(list)
    for task in tasks:
        if hasattr(task, 'delegate_to'):
            delegation_graph[task.agent.name].append(task.delegate_to.name)

    visited = set()
    def has_cycle(node):
        if node in visited:
            return True
        visited.add(node)
        return any(has_cycle(neighbor) for neighbor in delegation_graph[node])

    return any(has_cycle(node) for node in delegation_graph)

