from crewai import Agent, Task

class LoopProtectedTask(Task):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.max_delegations = 3
        self.delegation_count = 0

    def delegate(self, target_agent):
        if self.delegation_count >= self.max_delegations:
            return {'error': 'Max delegations exceeded'}
        self.delegation_count += 1
        return super().delegate(target_agent)

# Usage
research_task = LoopProtectedTask(
    description='Research Q3 sales...',
    agent=researcher,
    max_delegations=2
)

def validate_tool_output(tool_call):
    from pydantic import BaseModel, validator

    class ValidatedOutput(BaseModel):
        @validator('content')
        def check_realism(cls, v):
            hallucination_indicators = [
                'as an AI language model',
                'I cannot access real-time',
                'according to my training'
            ]
            if any(indicator in v.lower() for indicator in hallucination_indicators):
                raise ValueError('Possible hallucination detected')
            return v

    return ValidatedOutput(content=tool_call['output'])

# Integrate in agent callback
task.callback = lambda output: validate_tool_output(output)

from crewai import Crew

class ObjectiveAlignedCrew(Crew):
    def __init__(self, original_objective, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.original_objective = original_objective

    def create_task(self, description, agent):
        aligned_description = f"{description}\n\nCRITICAL: Stay focused on original objective: {self.original_objective}"
        return Task(description=aligned_description, agent=agent)

